template <typename T>
class Stack {
private:
    T* data;
    int top;
    int size;
public:
    Stack(int maxSize) {
        data = new T[maxSize];
        top = -1;
        size = maxSize;
    }
    void push(T item) {
        if (top == size - 1)
            cout << "Stack is full." << endl;
        else
            data++;
    }

T pop() { if(top == -1) { cout << "Stack is empty." << endl; return T(); } else { return data[top--]; } }   
};   
